## Implementação Funcional

```typescript
// project-manager.ts
import { spawn, Subprocess } from "bun";

interface SessionStats {
  turns: number;
  estimatedTokens: number;
  messagesSize: number;
  startTime: number;
}

interface ManagerConfig {
  maxTurns: number;           // Limite de turns por sessão
  maxEstimatedTokens: number; // Limite estimado de tokens
  maxSessionTimeMs: number;   // Timeout por sessão
  projectDir: string;
}

const CONFIG: ManagerConfig = {
  maxTurns: 25,
  maxEstimatedTokens: 150_000,  // ~75% de 200k
  maxSessionTimeMs: 30 * 60 * 1000, // 30 min
  projectDir: process.cwd(),
};

// Heurística: ~4 chars = 1 token (aproximado)
function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

class ProjectManager {
  private sessionCount = 0;
  private totalCost = 0;
  private currentRunner: Subprocess | null = null;
  private stats: SessionStats = this.freshStats();

  private freshStats(): SessionStats {
    return {
      turns: 0,
      estimatedTokens: 0,
      messagesSize: 0,
      startTime: Date.now(),
    };
  }

  async runSession(prompt: string): Promise<{ completed: boolean; reason: string }> {
    this.sessionCount++;
    this.stats = this.freshStats();

    console.log(`\n${"=".repeat(60)}`);
    console.log(`[Manager] Sessão #${this.sessionCount} iniciando...`);
    console.log(`${"=".repeat(60)}\n`);

    this.currentRunner = spawn({
      cmd: [
        "claude",
        "-p", prompt,
        "--output-format", "stream-json",
        "--print",
      ],
      cwd: CONFIG.projectDir,
      stdio: ["inherit", "pipe", "pipe"],
    });

    const decoder = new TextDecoder();
    const reader = this.currentRunner.stdout.getReader();
    let shouldTerminate = false;
    let terminateReason = "";

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const text = decoder.decode(value);

        for (const line of text.split("\n").filter(l => l.trim())) {
          try {
            const json = JSON.parse(line);
            const analysis = this.analyzeMessage(json);

            if (analysis.shouldTerminate) {
              shouldTerminate = true;
              terminateReason = analysis.reason;
              console.log(`\n[Manager] ⚠️  ${terminateReason}`);
              this.currentRunner.kill();
              break;
            }
          } catch {
            // Linha não é JSON válido, ignorar
          }
        }

        if (shouldTerminate) break;
      }
    } finally {
      reader.releaseLock();
    }

    await this.currentRunner.exited;

    return {
      completed: !shouldTerminate,
      reason: shouldTerminate ? terminateReason : "success",
    };
  }

  private analyzeMessage(json: any): { shouldTerminate: boolean; reason: string } {
    // Atualiza estatísticas baseado no tipo de mensagem
    if (json.type === "assistant" && json.message?.content) {
      this.stats.turns++;
      const content = JSON.stringify(json.message.content);
      this.stats.messagesSize += content.length;
      this.stats.estimatedTokens += estimateTokens(content);

      console.log(`[Manager] Turn ${this.stats.turns} | ~${this.stats.estimatedTokens.toLocaleString()} tokens estimados`);
    }

    if (json.type === "user" && json.message?.content) {
      const content = JSON.stringify(json.message.content);
      this.stats.estimatedTokens += estimateTokens(content);
    }

    if (json.type === "tool_result" && json.output) {
      this.stats.estimatedTokens += estimateTokens(json.output);
    }

    // Captura custo final
    if (json.type === "result" && json.total_cost_usd) {
      this.totalCost += json.total_cost_usd;
      console.log(`[Manager] Sessão custou: $${json.total_cost_usd.toFixed(4)}`);
      console.log(`[Manager] Custo total acumulado: $${this.totalCost.toFixed(4)}`);
    }

    // Verifica limites
    if (this.stats.turns >= CONFIG.maxTurns) {
      return { shouldTerminate: true, reason: `Limite de turns (${CONFIG.maxTurns})` };
    }

    if (this.stats.estimatedTokens >= CONFIG.maxEstimatedTokens) {
      return { shouldTerminate: true, reason: `Tokens estimados (${this.stats.estimatedTokens.toLocaleString()})` };
    }

    const elapsed = Date.now() - this.stats.startTime;
    if (elapsed >= CONFIG.maxSessionTimeMs) {
      return { shouldTerminate: true, reason: `Timeout (${CONFIG.maxSessionTimeMs / 1000}s)` };
    }

    return { shouldTerminate: false, reason: "" };
  }

  async runContinuousWork(initialPrompt: string) {
    let prompt = initialPrompt;

    while (true) {
      const result = await this.runSession(prompt);

      if (result.completed) {
        console.log(`\n[Manager] ✅ Trabalho completado naturalmente`);
        break;
      }

      console.log(`\n[Manager] 🔄 Reiniciando sessão limpa...`);
      console.log(`[Manager] Razão: ${result.reason}`);

      // Prompt de continuação
      prompt = `Sessão anterior foi interrompida para manter qualidade.
Leia claude-progress.txt para contexto completo.
Continue o trabalho de onde parou.
NÃO repita trabalho já feito - verifique o progresso primeiro.`;

      // Pequena pausa entre sessões
      await Bun.sleep(2000);
    }

    console.log(`\n${"=".repeat(60)}`);
    console.log(`[Manager] RESUMO FINAL`);
    console.log(`${"=".repeat(60)}`);
    console.log(`Sessões executadas: ${this.sessionCount}`);
    console.log(`Custo total: $${this.totalCost.toFixed(4)}`);
  }
}

// Entry point
const manager = new ProjectManager();
const initialPrompt = process.argv[2] || "Leia claude-progress.txt e continue o trabalho.";

manager.runContinuousWork(initialPrompt).catch(console.error);
```

